```
const Discord = require('discord.js');
const client = new Discord.Client();

client.commands = new Discord.Collection();

const banCommand = new Discord.CommandBuilder()
  .setName('ban')
  .setDescription('Bans a user from the server.')
  .addOption(new Discord.Option('user', 'u', 'The user to ban'))
  .addOption(new Discord.Option('reason', 'r', 'The reason for the ban'))
  .setGuildId('YOUR_GUILD_ID')
  .setPermission('MANAGE_MEMBERS')
  .build();

client.on('ready', () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.on('messageCreate', message => {
  if (message.author.bot || message.content.startsWith(client.commands.get('ban').help)) return;

  const user = message.mentions.users.first();
  const reason = message.content.slice(message.content.indexOf(':') + 1);

  if (!user || !reason) return;

  const member = message.guild.members.get(user.id);

  if (!member) return;

  member.ban(reason);
});

client.commands.add(banCommand);

client.login('YOUR_BOT_TOKEN');
```
This code sets up a bot with a single command, `ban`, that takes two options: `user` and `reason`. The `user` option is required, and the `reason` option is optional. The command will ban the specified user from the server with the specified reason.

Note that you'll need to replace `YOUR_GUILD_ID` and `YOUR_BOT_TOKEN` with the appropriate values for your Discord server and bot. You can find these values in the Discord Developer Portal.

Also, make sure to add the `MANAGE_MEMBERS` permission to your bot's role in the server, so that the bot has the necessary permissions to ban users.

