```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ncurses.h>

#define WIDTH 80
#define HEIGHT 25

// Game variables
int width, height;
char snake_body[100];
int snake_head = 0;
int food_x, food_y;
int score = 0;

// Functions
void update_snake(void);
void update_food(void);
void render_game(void);
void check_input(void);

int main(void)
{
    // Initialize ncurses
    initscr();
    cbreak();
    noecho();
    curs_set(0);

    // Get the game dimensions from the user
    printf("Enter the width and height of the game board (separated by a space): ");
    fgets(width, 3, stdin);
    fgets(height, 3, stdin);

    // Create the game window
