    wbkgd(window, A_NORMAL);
    wborder(window, 0, 0, 0, 0, 0, 0, 0, 0);
    wtitle(window, "Snake Game");

    // Initialize the game variables
    for (int i = 0; i < 100; i++) {
        snake_body[i] = ' ';
    }
    snake_head = 0;
    food_x = width / 2;
    food_y = height / 2;
    score = 0;

    // Game loop
    while (1) {
        // Update the snake
        update_snake();

        // Update the food
        update_food();

        // Render the game
        render_game();

        // Check for user input
        check_input();

        // Sleep for a bit to prevent the game from running too fast
        usleep(10000);
    }

    // Clean up
    delwin(window);
    endwin();

    return 0;
}

void update_snake(void)
{
    // Get the snake's new position based on user input
    int new_head = 0;
    switch (snake_body[snake_head]) {
        case 'A':
            new_head = 0;
            break;
        case 'B':
            new_head = 1;
            break;
        case 'C':
            new_head = 2;
            break;
        case 'D':
            new_head = 3;
            break;
    }

    // Check for collisions with the walls and itself
    if (new_head < 0 || new_head >= WIDTH || snake_body[new_head] != ' ' || collides_with_snake(new_head)) {
        // Reset the snake's position and decrease the score
        snake_head = 0;
        score -= 1;
    } else {
        // Move the snake's head to the new position
        snake_head = new_head;
    }
}

void update_food(void)
{
    // Generate a new position for the food
    int new_x = width / 2 + rand() % (WIDTH - 1);
    int new_y = height / 2 + rand() % (HEIGHT - 1);

    // Check for collisions with the walls
    if (new_x < 0 || new_x >= WIDTH || new_y < 0 || new_y >= HEIGHT) {
        // Reset the food's position
        food_x = width / 2;
        food_y = height / 2;
    } else {
        // Move the food to the new position
        food_x = new_x;
        food_y = new_y;
    }
}

void render_game(void)
{
    // Clear the game board
    for (int i = 0; i < WIDTH; i++) {
        for (int j = 0; j < HEIGHT; j++) {
            addch(i, j, ' ');
        }
    }

    // Draw the snake's body
    for (int i = 0; i < snake_head; i++) {
        addch(snake_body[i] - 'A', i, ' ');
    }

    // Draw the food
    addch(food_x, food_y, 'O');

    // Draw the score
    int score_width = 10;
    int score_height = 1;
    box(score_width, score_height, A_BOLD);
    text_color(A_NORMAL, "Score: %d", score);
}

void check_input(void)
{
    // Get the user's input
    int key = getch();

    // Handle arrow key presses
    if (key == KEY_UP || key == KEY_DOWN || key == KEY_LEFT || key == KEY_RIGHT) {
        // Update the snake's position based on the user input
        update_snake();
    }
}
